--
-- Table structure for table `agent_wallet_recharge_orders`
--

DROP TABLE IF EXISTS `agent_wallet_recharge_orders`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `agent_wallet_recharge_orders` (
  `id` int NOT NULL AUTO_INCREMENT,
  `user_id` int NOT NULL COMMENT '发起充值的代理商用户ID',
  `order_no` varchar(50) NOT NULL COMMENT '货款充值单号（微信 out_trade_no）',
  `amount` decimal(12,2) NOT NULL COMMENT '充值金额',
  `status` enum('pending','paid','cancelled') NOT NULL DEFAULT 'pending' COMMENT '充值单状态',
  `expire_at` datetime NOT NULL COMMENT '待支付过期时间',
  `paid_at` datetime DEFAULT NULL COMMENT '支付完成时间',
  `cancelled_at` datetime DEFAULT NULL COMMENT '关闭时间',
  `close_reason` varchar(255) DEFAULT NULL COMMENT '关闭原因',
  `last_prepay_at` datetime DEFAULT NULL COMMENT '最近一次拉起微信支付时间',
  `created_at` datetime NOT NULL,
  `updated_at` datetime NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `order_no` (`order_no`),
  KEY `agent_wallet_recharge_orders_user_id_status` (`user_id`,`status`),
  KEY `agent_wallet_recharge_orders_expire_at` (`expire_at`),
  CONSTRAINT `agent_wallet_recharge_orders_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

