DROP TABLE IF EXISTS `app_configs`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `app_configs` (
  `id` int NOT NULL AUTO_INCREMENT,
  `config_key` varchar(100) NOT NULL COMMENT '配置键名',
  `config_value` text COMMENT '配置值(JSON格式)',
  `config_type` varchar(20) DEFAULT 'string' COMMENT '数据类型: string/number/boolean/json/array',
  `category` varchar(50) DEFAULT 'general' COMMENT '配置分类: general/homepage/ui/commission/system',
  `description` varchar(255) DEFAULT NULL COMMENT '配置说明',
  `is_public` tinyint(1) DEFAULT '1' COMMENT '是否公开给前端: true-公开, false-仅后台',
  `status` tinyint DEFAULT '1' COMMENT '状态: 1-启用, 0-禁用',
  `created_at` datetime NOT NULL,
  `updated_at` datetime NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `config_key` (`config_key`),
  KEY `app_configs_config_key` (`config_key`),
  KEY `app_configs_category` (`category`)
) ENGINE=InnoDB AUTO_INCREMENT=310 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
