DROP TABLE IF EXISTS `banners`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `banners` (
  `id` int NOT NULL AUTO_INCREMENT,
  `title` varchar(100) DEFAULT NULL COMMENT '标题/备注',
  `subtitle` varchar(200) DEFAULT NULL COMMENT '副标题/描述文字',
  `kicker` varchar(100) DEFAULT NULL COMMENT '顶部小标（如 NEW / 限时活动）',
  `product_id` int DEFAULT NULL COMMENT '关联商品ID（设置后自动带入商品首图和跳转目标）',
  `image_url` varchar(500) DEFAULT NULL COMMENT '图片URL（优先于商品首图）',
  `link_type` varchar(20) DEFAULT 'none' COMMENT '链接类型: none/product/activity/group_buy/slash/lottery/page/url',
  `link_value` varchar(255) DEFAULT NULL COMMENT '链接值: 商品ID/页面路径/外部URL',
  `position` varchar(50) DEFAULT 'home' COMMENT '展示位置: home/category/activity',
  `sort_order` int DEFAULT '0' COMMENT '排序权重',
  `start_time` datetime DEFAULT NULL COMMENT '开始展示时间',
  `end_time` datetime DEFAULT NULL COMMENT '结束展示时间',
  `status` tinyint DEFAULT '1' COMMENT '状态: 1-启用, 0-禁用',
  `created_at` datetime NOT NULL,
  `updated_at` datetime NOT NULL,
  PRIMARY KEY (`id`),
  KEY `product_id` (`product_id`),
  CONSTRAINT `banners_ibfk_1` FOREIGN KEY (`product_id`) REFERENCES `products` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

