--
-- Table structure for table `mass_messages`
--

DROP TABLE IF EXISTS `mass_messages`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `mass_messages` (
  `id` int NOT NULL AUTO_INCREMENT,
  `title` varchar(200) NOT NULL COMMENT '消息标题',
  `content` text NOT NULL COMMENT '消息内容',
  `content_type` enum('text','image','link','miniapp') DEFAULT 'text' COMMENT '内容类型',
  `target_type` enum('all','role','tag','specific') NOT NULL COMMENT '目标类型',
  `target_roles` json DEFAULT NULL COMMENT '目标角色',
  `target_users` json DEFAULT NULL COMMENT '特定用户ID列表',
  `target_tags` json DEFAULT NULL COMMENT '用户标签',
  `send_type` enum('immediate','scheduled') DEFAULT 'immediate' COMMENT '发送类型',
  `scheduled_at` datetime DEFAULT NULL COMMENT '定时发送时间',
  `status` enum('draft','pending','sending','completed','failed','cancelled') DEFAULT 'draft' COMMENT '状态',
  `total_count` int DEFAULT '0' COMMENT '目标用户总数',
  `sent_count` int DEFAULT '0' COMMENT '已发送数',
  `read_count` int DEFAULT '0' COMMENT '已读数',
  `fail_count` int DEFAULT '0' COMMENT '失败数',
  `result_details` json DEFAULT NULL COMMENT '发送结果详情',
  `error_message` text COMMENT '错误信息',
  `created_by` int DEFAULT NULL,
  `sent_at` datetime DEFAULT NULL COMMENT '实际发送时间',
  `completed_at` datetime DEFAULT NULL COMMENT '完成时间',
  `created_at` datetime NOT NULL,
  `updated_at` datetime NOT NULL,
  PRIMARY KEY (`id`),
  KEY `created_by` (`created_by`),
  CONSTRAINT `mass_messages_ibfk_1` FOREIGN KEY (`created_by`) REFERENCES `admins` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

