  `download_count` int DEFAULT '0' COMMENT '下载/使用次数',
  `sort_order` int DEFAULT '0' COMMENT '排序权重',
  `status` tinyint DEFAULT '1' COMMENT '状态: 1-启用, 0-禁用',
  `created_at` datetime NOT NULL,
  `updated_at` datetime NOT NULL,
  PRIMARY KEY (`id`),
