DROP TABLE IF EXISTS `n_fund_requests`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `n_fund_requests` (
  `id` int NOT NULL AUTO_INCREMENT,
  `requester_id` int NOT NULL COMMENT '申请人（小n）的 user_id',
  `leader_id` int NOT NULL COMMENT '目标大N的 user_id',
  `amount` decimal(12,2) NOT NULL COMMENT '申请金额（元）',
  `status` enum('pending','approved','rejected') DEFAULT 'pending' COMMENT '状态：pending=待审核，approved=已通过，rejected=已驳回',
  `note` varchar(255) DEFAULT NULL COMMENT '申请备注（小n填写）',
  `reject_reason` varchar(255) DEFAULT NULL COMMENT '驳回原因（大N填写）',
  `reviewed_at` datetime DEFAULT NULL COMMENT '审核时间',
  `created_at` datetime NOT NULL,
  `updated_at` datetime NOT NULL,
  PRIMARY KEY (`id`),
  KEY `requester_id` (`requester_id`),
  KEY `leader_id` (`leader_id`),
  CONSTRAINT `n_fund_requests_ibfk_1` FOREIGN KEY (`requester_id`) REFERENCES `users` (`id`) ON UPDATE CASCADE,
  CONSTRAINT `n_fund_requests_ibfk_2` FOREIGN KEY (`leader_id`) REFERENCES `users` (`id`) ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

