DROP TABLE IF EXISTS `n_region_rules`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `n_region_rules` (
  `id` int NOT NULL AUTO_INCREMENT,
  `user_id` int NOT NULL COMMENT '所属 N3 用户ID',
  `title` varchar(100) DEFAULT NULL COMMENT '规则名称',
  `province_keyword` varchar(50) DEFAULT NULL COMMENT '省关键词',
  `city_keyword` varchar(50) DEFAULT NULL COMMENT '市关键词',
  `district_keyword` varchar(50) DEFAULT NULL COMMENT '区/县关键词',
  `station_keywords` text COMMENT '门店关键词 JSON 数组',
  `profit_rate` decimal(6,4) NOT NULL DEFAULT '0.0200' COMMENT 'N3 发货利润比例',
  `sort_order` int NOT NULL DEFAULT '0' COMMENT '排序值，越小越优先',
  `status` enum('active','inactive') NOT NULL DEFAULT 'active' COMMENT '状态',
  `created_at` datetime NOT NULL,
  `updated_at` datetime NOT NULL,
  PRIMARY KEY (`id`),
  KEY `n_region_rules_user_id_status` (`user_id`,`status`),
  KEY `n_region_rules_status_sort_order` (`status`,`sort_order`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
