--
-- Table structure for table `orders`
--

DROP TABLE IF EXISTS `orders`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `orders` (
  `id` int NOT NULL AUTO_INCREMENT,
  `order_no` varchar(50) NOT NULL COMMENT '订单号',
  `buyer_id` int NOT NULL COMMENT '购买者ID',
  `distributor_id` int DEFAULT NULL COMMENT '分销商ID',
  `distributor_role` tinyint DEFAULT NULL COMMENT '下单时分销商角色（锁定）',
  `product_id` int NOT NULL COMMENT '商品ID',
  `quantity` int DEFAULT '1' COMMENT '数量',
  `total_amount` decimal(10,2) NOT NULL COMMENT '订单总金额',
  `actual_price` decimal(10,2) NOT NULL COMMENT '实际支付价格',
  `fulfillment_type` varchar(20) DEFAULT NULL COMMENT '履约类型: Company/Partner',
  `fulfillment_partner_id` int DEFAULT NULL COMMENT '实际发货的Partner ID',
  `agent_id` int DEFAULT NULL COMMENT '所属代理商ID（团队归属）',
  `tracking_no` varchar(100) DEFAULT NULL COMMENT '物流单号',
  `logistics_company` varchar(20) DEFAULT NULL COMMENT '物流公司代码（SF/YTO/ZTO/YD/EMS等）',
  `status` varchar(20) DEFAULT 'pending' COMMENT '订单状态: pending/paid/agent_confirmed/shipping_requested/shipped/completed/cancelled/refunded',
  `sku_id` int DEFAULT NULL COMMENT 'SKU ID',
  `address_id` int DEFAULT NULL COMMENT '收货地址ID',
  `address_snapshot` text COMMENT '收货地址快照（JSON）',
  `remark` varchar(255) DEFAULT NULL COMMENT '订单备注',
  `paid_at` datetime DEFAULT NULL COMMENT '支付时间',
  `agent_confirmed_at` datetime DEFAULT NULL COMMENT '代理人确认时间',
  `shipping_requested_at` datetime DEFAULT NULL COMMENT '申请发货时间',
  `shipped_at` datetime DEFAULT NULL COMMENT '发货时间',
  `completed_at` datetime DEFAULT NULL COMMENT '完成时间',
  `settlement_at` datetime DEFAULT NULL COMMENT '佣金结算时间（完成后+7天）',
  `commission_settled` tinyint DEFAULT '0' COMMENT '佣金是否已结算: 0-未结算, 1-已结算',
  `completion_processed` tinyint(1) NOT NULL DEFAULT '0' COMMENT ': 0-, 1-processOrderCompletion ',
  `middle_commission_total` decimal(10,2) DEFAULT '0.00' COMMENT '中间层级佣金总额（发货利润扣除用）',
  `shipping_fee` decimal(10,2) DEFAULT '0.00' COMMENT '运费金额，包邮为0',
  `platform_stock_deducted` tinyint DEFAULT '1' COMMENT '创建订单时是否扣了平台库存: 1-已扣, 0-未扣（走代理商云库存）',
  `locked_agent_cost` decimal(10,2) DEFAULT NULL COMMENT '下单时锁定的代理商进货价（单价），发货利润以此为准',
  `parent_order_id` int DEFAULT NULL COMMENT '父订单ID（拆单时子订单指向父订单）',
  `coupon_id` int DEFAULT NULL COMMENT '使用的优惠券ID（user_coupons.id）',
  `coupon_discount` decimal(10,2) DEFAULT '0.00' COMMENT '优惠券抵扣金额',
  `points_used` int DEFAULT '0' COMMENT '本单消耗积分数量',
  `points_discount` decimal(10,2) DEFAULT '0.00' COMMENT '积分抵扣金额（points_used × 0.1 元/积分）',
  `member_discount_rate` decimal(4,2) DEFAULT '1.00' COMMENT '下单时锁定的会员折扣比例',
  `delivery_type` enum('express','pickup') DEFAULT 'express' COMMENT '配送方式: express=快递, pickup=到店自提',
  `pickup_station_id` int DEFAULT NULL COMMENT '自提服务站点ID',
  `pickup_code` varchar(16) DEFAULT NULL COMMENT '16位大写字母数字核销码（工人手动输入用）',
  `pickup_qr_token` varchar(64) DEFAULT NULL COMMENT '二维码扫码页面token（SHA256）',
  `verified_at` datetime DEFAULT NULL COMMENT '自提核销完成时间',
  `created_at` datetime NOT NULL,
  `updated_at` datetime NOT NULL,
  `payment_method` varchar(20) DEFAULT NULL COMMENT '支付方式: wechat/wallet',
  `n_region_rule_id` int DEFAULT NULL COMMENT '命中的 N3 区域规则ID',
  `n_region_owner_id` int DEFAULT NULL COMMENT '获得 N3 发货利润的用户ID',
  `n_region_profit_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT 'N3 发货利润金额',
  `n_region_match_scope` varchar(20) DEFAULT NULL COMMENT 'N3 命中范围: address/station/both',
  `n_region_snapshot` text COMMENT 'N3 区域命中快照(JSON)',
  `verified_station_id` int DEFAULT NULL COMMENT '实际核销门店ID',
  `verified_by_type` varchar(20) DEFAULT NULL COMMENT '核销人身份类型: user/portal',
  `verified_by_user_id` int DEFAULT NULL COMMENT '核销人用户ID',
  `verified_by_portal_account_id` int DEFAULT NULL COMMENT '核销人门户账号ID',
  `shipping_agent_id` int DEFAULT NULL COMMENT '实际发货代理ID（链路上第一个有库存的代理）',
  `shipping_agent_role` tinyint DEFAULT NULL COMMENT '发货代理下单时的角色等级',
  `parent_chain_snapshot` text COMMENT '下单时 parent_id 链路快照（JSON 数组，记录每级用户ID和角色）',
  `distribution_trace` text COMMENT '分销佣金追溯（JSON，记录每笔佣金分配明细）',
  PRIMARY KEY (`id`),
  UNIQUE KEY `order_no` (`order_no`),
  KEY `distributor_id` (`distributor_id`),
  KEY `product_id` (`product_id`),
  KEY `sku_id` (`sku_id`),
  KEY `address_id` (`address_id`),
  KEY `coupon_id` (`coupon_id`),
  KEY `pickup_station_id` (`pickup_station_id`),
  KEY `orders_buyer_id_status` (`buyer_id`,`status`),
  KEY `orders_agent_id_status` (`agent_id`,`status`),
  KEY `idx_orders_verified_station_id` (`verified_station_id`),
  KEY `idx_orders_verified_by_type` (`verified_by_type`),
  CONSTRAINT `orders_ibfk_1` FOREIGN KEY (`buyer_id`) REFERENCES `users` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `orders_ibfk_2` FOREIGN KEY (`distributor_id`) REFERENCES `users` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `orders_ibfk_3` FOREIGN KEY (`product_id`) REFERENCES `products` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `orders_ibfk_4` FOREIGN KEY (`sku_id`) REFERENCES `product_skus` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `orders_ibfk_5` FOREIGN KEY (`address_id`) REFERENCES `addresses` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `orders_ibfk_6` FOREIGN KEY (`coupon_id`) REFERENCES `user_coupons` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `orders_ibfk_7` FOREIGN KEY (`pickup_station_id`) REFERENCES `service_stations` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=91 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

