--
-- Table structure for table `point_logs`
--

DROP TABLE IF EXISTS `point_logs`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `point_logs` (
  `id` int NOT NULL AUTO_INCREMENT,
  `user_id` int NOT NULL COMMENT '用户ID',
  `points` int NOT NULL COMMENT '积分变动量（正=收入 负=支出/过期）',
  `type` varchar(30) NOT NULL COMMENT '类型: register/purchase/share/review/checkin/invite_success/group_start/group_success/redeem/expire',
  `ref_id` varchar(64) DEFAULT NULL COMMENT '关联业务ID（订单号/分享ID等）',
  `remark` varchar(200) DEFAULT NULL COMMENT '说明文字（前端展示用）',
  `balance_after` int DEFAULT '0' COMMENT '操作后余额快照',
  `created_at` datetime NOT NULL,
  PRIMARY KEY (`id`),
  KEY `user_id` (`user_id`),
  CONSTRAINT `point_logs_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=555 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

