--
-- Table structure for table `products`
--

DROP TABLE IF EXISTS `products`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `products` (
  `id` int NOT NULL AUTO_INCREMENT,
  `name` varchar(200) NOT NULL COMMENT '商品名称',
  `category_id` int DEFAULT NULL COMMENT '类目ID',
  `description` text COMMENT '商品描述',
  `images` text COMMENT '商品图片URLs（JSON数组）',
  `detail_images` text COMMENT '商品详情图URLs（JSON数组，长图拼接展示）',
  `retail_price` decimal(10,2) NOT NULL COMMENT '零售价 ¥299',
  `member_price` decimal(10,2) DEFAULT NULL COMMENT '会员价（兼容旧字段）',
  `wholesale_price` decimal(10,2) DEFAULT NULL COMMENT '批发价（兼容旧字段）',
  `price_member` decimal(10,2) DEFAULT NULL COMMENT '会员价 ¥239',
  `price_leader` decimal(10,2) DEFAULT NULL COMMENT '团长价 ¥209',
  `price_agent` decimal(10,2) DEFAULT NULL COMMENT '代理价 ¥150',
  `cost_price` decimal(10,2) DEFAULT NULL COMMENT '成本价/进货价 - 供应商给平台的价格',
  `commission_rate_1` decimal(4,2) DEFAULT NULL COMMENT '一级分销比例 (e.g. 0.20), 空则用默认',
  `commission_rate_2` decimal(4,2) DEFAULT NULL COMMENT '二级分销比例 (e.g. 0.10), 空则用默认',
  `commission_amount_1` decimal(10,2) DEFAULT NULL COMMENT '一级分销固定金额 (e.g. 10.00), 优先于比例',
  `commission_amount_2` decimal(10,2) DEFAULT NULL COMMENT '二级分销固定金额 (e.g. 5.00), 优先于比例',
  `commission_rate_3` decimal(4,2) DEFAULT NULL COMMENT '三级分销比例 (e.g. 0.05), 空则用默认',
  `commission_amount_3` decimal(10,2) DEFAULT NULL COMMENT '三级分销固定金额 (e.g. 3.00), 优先于比例',
  `ai_review_status` enum('pending','approved','rejected') DEFAULT 'pending' COMMENT 'AI审查状态',
  `ai_review_reason` varchar(500) DEFAULT NULL COMMENT 'AI审查原因',
  `stock` int DEFAULT '0' COMMENT '商品总库存',
  `status` tinyint DEFAULT '1' COMMENT '状态: 1-上架, 0-下架',
  `custom_commissions` json DEFAULT NULL COMMENT '段位定制佣金配置，例如 {"fixed": {"MEMBER": 10, "LEADER": 20}, "rate": {"AGENT": 0.15}}',
  `view_count` int DEFAULT '0' COMMENT '商品展示页访问次数',
  `purchase_count` int DEFAULT '0' COMMENT '近30天内购买单数（定期刷新）',
  `heat_score` int DEFAULT '0' COMMENT '热度分（purchase×40+view×10+manual×50，呢单排行用）',
  `manual_weight` tinyint DEFAULT '0' COMMENT '后台手动热度权重 0-100，运营可干预榜单',
  `heat_updated_at` datetime DEFAULT NULL COMMENT '热度最近刷新时间',
  `market_price` decimal(10,2) DEFAULT NULL COMMENT '市场价/原价（划线价）',
  `created_at` datetime NOT NULL,
  `updated_at` datetime NOT NULL,
  `discount_exempt` tinyint(1) NOT NULL DEFAULT '0',
  `product_tag` varchar(50) NOT NULL DEFAULT 'normal',
  `supports_pickup` tinyint NOT NULL DEFAULT '0' COMMENT '是否支持到店自提 0否 1是',
  `visible_in_mall` tinyint(1) NOT NULL DEFAULT '1' COMMENT '1=商城可见 0=商城不可见（限时活动等仍可选用）',
  `enable_coupon` tinyint NOT NULL DEFAULT '1' COMMENT '是否允许使用优惠券 1是 0否',
  `enable_group_buy` tinyint NOT NULL DEFAULT '0' COMMENT '是否参与拼团 1是 0否',
  PRIMARY KEY (`id`),
  KEY `category_id` (`category_id`),
  CONSTRAINT `products_ibfk_1` FOREIGN KEY (`category_id`) REFERENCES `categories` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=12 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

