--
-- Table structure for table `user_mass_messages`
--

DROP TABLE IF EXISTS `user_mass_messages`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `user_mass_messages` (
  `id` int NOT NULL AUTO_INCREMENT,
  `user_id` int DEFAULT NULL,
  `mass_message_id` int DEFAULT NULL,
  `status` enum('unread','read') DEFAULT 'unread' COMMENT '阅读状态',
  `received_at` datetime DEFAULT NULL COMMENT '接收时间',
  `read_at` datetime DEFAULT NULL COMMENT '阅读时间',
  PRIMARY KEY (`id`),
  KEY `user_id` (`user_id`),
  KEY `mass_message_id` (`mass_message_id`),
  CONSTRAINT `user_mass_messages_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `user_mass_messages_ibfk_2` FOREIGN KEY (`mass_message_id`) REFERENCES `mass_messages` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=207 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

