--
-- Table structure for table `users`
--

DROP TABLE IF EXISTS `users`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `users` (
  `id` int NOT NULL AUTO_INCREMENT,
  `openid` varchar(100) NOT NULL COMMENT '微信openid',
  `member_no` varchar(20) DEFAULT NULL COMMENT '会员编号，格式 M+年月+流水号，如 M202600001，注册时自动生成',
  `nickname` varchar(100) DEFAULT NULL COMMENT '昵称',
  `avatar_url` varchar(255) DEFAULT NULL COMMENT '头像URL',
  `phone` varchar(20) DEFAULT NULL COMMENT '手机号码',
  `role_level` tinyint DEFAULT '0' COMMENT '角色等级: 0-普通用户, 1-会员, 2-团长, 3-代理商',
  `agent_level` tinyint DEFAULT '1' COMMENT '代理商级别（仅 role_level=3 时有效）: 1-一级代理, 2-二级代理, 3-三级代理',
  `parent_id` int DEFAULT NULL COMMENT '上级用户ID',
  `parent_openid` varchar(100) DEFAULT NULL COMMENT '上级openid（冗余字段）',
  `agent_id` int DEFAULT NULL COMMENT '所属代理商ID',
  `stock_count` int DEFAULT '0' COMMENT '云仓库存（仅代理商有效）',
  `invite_code` varchar(8) DEFAULT NULL COMMENT '8位数字唯一邀请码',
  `balance` decimal(10,2) DEFAULT '0.00' COMMENT '可提现余额',
  `referee_count` int DEFAULT '0' COMMENT '直推人数',
  `order_count` int DEFAULT '0' COMMENT '累计订单数',
  `total_sales` decimal(12,2) DEFAULT '0.00' COMMENT '累计销售额',
  `last_login` datetime DEFAULT NULL COMMENT '最后登录时间',
  `joined_team_at` datetime DEFAULT NULL COMMENT '加入团队时间（绑定上级时设置）',
  `preferences` json DEFAULT NULL COMMENT '用户偏好设置 JSON { style, categories }',
  `debt_amount` decimal(10,2) DEFAULT '0.00' COMMENT '欠款金额（佣金追回余额不足时的待还金额）',
  `growth_value` decimal(12,2) DEFAULT '0.00' COMMENT '消费成长值（累计消费金额，不减不清零）',
  `discount_rate` decimal(4,2) DEFAULT '1.00' COMMENT '当前会员折扣比例，由成长值阶梯自动更新',
  `status` tinyint DEFAULT '1' COMMENT '账号状态: 1-正常 0-封禁',
  `remark` varchar(500) DEFAULT NULL COMMENT '内部备注（管理员可编辑）',
  `tags` varchar(255) DEFAULT NULL COMMENT '内部标签 JSON数组字符串，如 ["VIP","高活跃"]',
  `created_at` datetime NOT NULL,
  `updated_at` datetime NOT NULL,
  `purchase_level_code` varchar(32) DEFAULT NULL COMMENT '拿货等级编码（仅影响价格）',
  `participate_distribution` tinyint NOT NULL DEFAULT '0' COMMENT '是否参与分销展示: 0-否 1-是（商务中心入口）',
  `n_leader_id` int DEFAULT NULL COMMENT 'N路径上级大N的user_id（role_level=6时指向大N）',
  `benefit_parent_id` int DEFAULT NULL COMMENT '收益上级ID（C/B同级脱离后可与 parent_id 分离）',
  `cb_detached_at` datetime DEFAULT NULL COMMENT 'C/B路径同级脱离时间',
  `cb_detached_from_user_id` int DEFAULT NULL COMMENT 'C/B路径同级脱离时的原收益上级 user_id',
  `cb_detach_level` tinyint DEFAULT NULL COMMENT 'C/B路径发生同级脱离时的角色等级',
  `n_level` tinyint DEFAULT NULL COMMENT 'N路径层级: 1=N1, 2=N2, 3=N3',
  `n_parent_id` int DEFAULT NULL COMMENT 'N路径直接上级 user_id',
  PRIMARY KEY (`id`),
  UNIQUE KEY `openid` (`openid`),
  UNIQUE KEY `member_no` (`member_no`),
  UNIQUE KEY `invite_code` (`invite_code`),
  UNIQUE KEY `invite_code_2` (`invite_code`),
  UNIQUE KEY `invite_code_3` (`invite_code`),
